import{_ as n,o as a,c as t,a2 as o}from"./chunks/framework.Bix3-HpO.js";const m=JSON.parse('{"title":"Link Checker","description":"Automatic Broken Link Detection in Nonaki","frontmatter":{"title":"Link Checker","description":"Automatic Broken Link Detection in Nonaki","weight":50,"extra":{"order":50},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/link-checker"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/link-checker"}],["meta",{"property":"og:title","content":"Link Checker"}],["meta",{"property":"og:description","content":"Automatic Broken Link Detection in Nonaki"}],["meta",{"name":"twitter:title","content":"Link Checker"}],["meta",{"name":"twitter:description","content":"Automatic Broken Link Detection in Nonaki"}]]},"headers":[],"relativePath":"docs/nonaki/link-checker.md","filePath":"docs/nonaki/link-checker.md"}'),i={name:"docs/nonaki/link-checker.md"};function r(c,e,s,k,d,h){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="link-checker" tabindex="-1">Link Checker <a class="header-anchor" href="#link-checker" aria-label="Permalink to &quot;Link Checker&quot;">​</a></h1><p>Nonaki automatically checks whether your redirect destinations are still reachable and flags any that return an error or are unreachable.</p><hr><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>Once a day, Nonaki sends a HEAD request to each active redirect destination and records the HTTP response code. Links that return a <code>4xx</code> or <code>5xx</code> response, or that time out, are marked as broken.</p><p>Checks run in the background via WordPress cron and process links in small batches to avoid timeouts on sites with a large number of links.</p><hr><h2 id="broken-link-badge" tabindex="-1">Broken Link Badge <a class="header-anchor" href="#broken-link-badge" aria-label="Permalink to &quot;Broken Link Badge&quot;">​</a></h2><p>When a link&#39;s destination is unreachable, a <code>broken</code> badge appears on its row in the Links view. The badge is removed automatically the next time the checker runs and the link responds successfully.</p><hr><h2 id="email-digest" tabindex="-1">Email Digest <a class="header-anchor" href="#email-digest" aria-label="Permalink to &quot;Email Digest&quot;">​</a></h2><p>Nonaki sends an email notification when links become broken — meaning only links that were working on the previous check and are now failing. Links that were already flagged as broken are not included again.</p><p>The email goes to the WordPress admin email address and lists each newly broken link with its destination URL and the HTTP response code received.</p><hr><h2 id="on-demand-check" tabindex="-1">On-Demand Check <a class="header-anchor" href="#on-demand-check" aria-label="Permalink to &quot;On-Demand Check&quot;">​</a></h2><p>You can run a link check at any time without waiting for the daily cron. Go to <strong>Links</strong> and click <code>Check Links</code> button on the top toolbar. Results are shown inline — and each broken link displays a &quot;broken&quot; red badge.</p>',16)])])}const p=n(i,[["render",r]]);export{m as __pageData,p as default};
